#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/*
 * CPU Pipeline Simulator
 * Demonstrates instruction pipelining with 5 stages:
 * IF (Instruction Fetch), ID (Decode), EX (Execute), MEM (Memory), WB (Write Back)
 */

#define NUM_REGISTERS 8
#define PIPELINE_DEPTH 5
#define PROGRAM_SIZE 10

// Instruction structure
typedef struct {
 int opcode; // Operation code
 int rd; // Destination register
 int rs; // Source register 1
 int rt; // Source register 2
 int imm; // Immediate value/address
 int pc; // Program counter value
} Instruction;

// Pipeline stage states
typedef enum {
 STAGE_IF, STAGE_ID, STAGE_EX, STAGE_MEM, STAGE_WB, STAGE_DONE
} StageType;

// Current instruction in pipeline
typedef struct {
 Instruction instr;
 StageType stage;
 int result;
 int executed;
} PipelineRegister;

// CPU State
typedef struct {
 int registers[NUM_REGISTERS];
 int pc;
 int memory[256];
 int zero_flag;
 int negative_flag;
} CPU;

// Initialize CPU
void init_cpu(CPU *cpu) {
 memset(cpu->registers, 0, sizeof(cpu->registers));
 cpu->pc = 0;
 cpu->zero_flag = 0;
 cpu->negative_flag = 0;
 memset(cpu->memory, 0, sizeof(cpu->memory));
}

// Create instruction
Instruction make_instruction(int opcode, int rd, int rs, int rt, int imm) {
 Instruction instr;
 instr.opcode = opcode;
 instr.rd = rd;
 instr.rs = rs;
 instr.rt = rt;
 instr.imm = imm;
 return instr;
}

// Stage 1: Instruction Fetch
void stage_if(CPU *cpu, Instruction *instr, int *fetched, int program[], int prog_size) {
 if (cpu->pc < prog_size) {
 *instr = make_instruction(
 (program[cpu->pc] >> 24) & 0xFF,
 (program[cpu->pc] >> 21) & 0x7,
 (program[cpu->pc] >> 18) & 0x7,
 (program[cpu->pc] >> 15) & 0x7,
 program[cpu->pc] & 0x7FFF
 );
 instr->pc = cpu->pc;
 *fetched = 1;
 printf(" [IF] : Fetched instruction at PC=%d\n", cpu->pc);
 cpu->pc++;
 } else {
 *fetched = 0;
 }
}

// Stage 2: Instruction Decode
void stage_id(CPU *cpu, Instruction *instr, int *decoded) {
 if (!instr->opcode) { *decoded = 0; return; }

 char *op_names[] = {"NOP", "ADD", "SUB", "MUL", "LOAD", "STORE", "JUMP", "BEQ", "HALT"};
 int op_idx = instr->opcode < 8 ? instr->opcode : 0;

 printf(" [ID] : Decoded %s (R%d <- R%d, R%d), imm=%d\n", 
 op_names[op_idx], instr->rd, instr->rs, instr->rt, instr->imm);

 // Get register values for execution
 // In real CPU, this would be in register file read port
 *decoded = 1;
}

// Stage 3: Execute (ALU operation)
int stage_ex(CPU *cpu, Instruction *instr, int *executed) {
 if (!instr->opcode) { *executed = 0; return 0; }

 int rs_val = cpu->registers[instr->rs];
 int rt_val = cpu->registers[instr->rt];
 int result = 0;

 switch(instr->opcode) {
 case 1: // ADD
 result = rs_val + rt_val;
 printf(" [EX] : ADD: %d + %d = %d\n", rs_val, rt_val, result);
 break;
 case 2: // SUB
 result = rs_val - rt_val;
 printf(" [EX] : SUB: %d - %d = %d\n", rs_val, rt_val, result);
 break;
 case 3: // MUL
 result = rs_val * rt_val;
 printf(" [EX] : MUL: %d * %d = %d\n", rs_val, rt_val, result);
 break;
 case 6: // JUMP
 printf(" [EX] : JUMP to PC=%d\n", instr->imm);
 result = instr->imm;
 break;
 case 7: // BEQ
 printf(" [EX] : BEQ check: %d == %d? %s\n", rs_val, rt_val, 
 (rs_val == rt_val) ? "YES" : "NO");
 result = (rs_val == rt_val) ? instr->imm : -1;
 break;
 default:
 *executed = 0;
 return 0;
 }

 cpu->zero_flag = (result == 0);
 cpu->negative_flag = (result < 0);
 *executed = 1;
 return result;
}

// Stage 4: Memory Access
int stage_mem(CPU *cpu, Instruction *instr, int alu_result, int *mem_accessed) {
 if (!instr->opcode) { *mem_accessed = 0; return alu_result; }

 switch(instr->opcode) {
 case 4: // LOAD
 printf(" [MEM] : LOAD from memory[%d] = %d\n", 
 instr->imm, cpu->memory[instr->imm]);
 *mem_accessed = 1;
 return cpu->memory[instr->imm];
 case 5: // STORE
 printf(" [MEM] : STORE to memory[%d] = %d\n", 
 instr->imm, alu_result);
 cpu->memory[instr->imm] = alu_result;
 *mem_accessed = 1;
 return alu_result;
 default:
 printf(" [MEM] : No memory access\n");
 *mem_accessed = 0;
 return alu_result;
 }
}

// Stage 5: Write Back
void stage_wb(CPU *cpu, Instruction *instr, int mem_result, int *wb_done) {
 if (!instr->opcode) { *wb_done = 0; return; }

 // Skip for control instructions and stores
 if (instr->opcode == 6 || instr->opcode == 7 || instr->opcode == 5) {
 printf(" [WB] : No write back (control/store)\n");
 *wb_done = 1;
 return;
 }

 printf(" [WB] : Writing %d to R%d\n", mem_result, instr->rd);
 cpu->registers[instr->rd] = mem_result;
 *wb_done = 1;
}

// Print pipeline state
void print_pipeline(PipelineRegister pipeline[]) {
 char *stage_names[] = {"IF", "ID", "EX", "MEM", "WB"};
 printf("Pipeline: [");
 for (int i = 0; i < PIPELINE_DEPTH; i++) {
 if (pipeline[i].executed) {
 printf("%s:I%d", stage_names[i], pipeline[i].instr.pc);
 if (i < PIPELINE_DEPTH - 1) printf(" -> ");
 }
 }
 printf("]\n");
}

// Main pipeline simulation
int main() {
 CPU cpu;
 init_cpu(&cpu);

 // Set initial register values
 cpu.registers[0] = 10; // R0 = 10
 cpu.registers[1] = 20; // R1 = 20
 cpu.registers[2] = 5; // R2 = 5

 // Sample program (encoded as integers)
 // ADD R3, R0, R1 -> R3 = 30
 // SUB R4, R3, R2 -> R4 = 25
 // MUL R5, R3, R2 -> R5 = 150
 int program[] = {
 0x0100C0A0, // ADD R3, R0, R1
 0x0200D0C8, // SUB R4, R3, R2
 0x0300E0C8, // MUL R5, R3, R2
 0x0400F0C8, // LOAD R6 from address 200
 0x0500F064, // STORE R5 to address 100
 0xFF000000 // HALT
 };
 int prog_size = sizeof(program) / sizeof(program[0]);

 // Set some memory values
 cpu.memory[200] = 42;

 printf("\n========================================\n");
 printf(" CPU PIPELINE SIMULATION\n");
 printf("========================================\n\n");

 // Pipeline registers
 PipelineRegister pipeline[PIPELINE_DEPTH];
 memset(pipeline, 0, sizeof(pipeline));

 int cycles = 0;
 int program_complete = 0;

 while (!program_complete && cycles < 20) {
 printf("\n--- Cycle %d ---\n", ++cycles);

 // Process each stage in reverse order (data flows forward)
 // WB Stage
 int wb_done = 0;
 stage_wb(&cpu, &pipeline[4].instr, pipeline[4].result, &wb_done);
 if (wb_done && pipeline[4].instr.opcode == 0xFF) {
 program_complete = 1;
 }

 // MEM Stage
 int mem_result = stage_mem(&cpu, &pipeline[3].instr, pipeline[3].result, 
 &pipeline[4].executed);
 if (pipeline[4].executed) {
 pipeline[4].result = mem_result;
 }

 // EX Stage
 int ex_result = stage_ex(&cpu, &pipeline[2].instr, &pipeline[3].executed);
 if (pipeline[3].executed) {
 pipeline[3].result = ex_result;
 }

 // ID Stage
 int decoded = 0;
 stage_id(&cpu, &pipeline[1].instr, &decoded);
 pipeline[2].executed = decoded;
 if (decoded) {
 pipeline[2].instr = pipeline[1].instr;
 }

 // IF Stage
 int fetched = 0;
 stage_if(&cpu, &pipeline[0].instr, fetched, program, prog_size);
 if (fetched) {
 pipeline[1].executed = 1;
 pipeline[1].instr = pipeline[0].instr;
 }

 // Handle special cases
 if (pipeline[2].instr.opcode == 6) { // JUMP
 cpu.pc = pipeline[2].result;
 // Flush pipeline
 memset(&pipeline[0], 0, sizeof(pipeline));
 printf(" [PIPELINE FLUSH] Due to jump\n");
 }

 print_pipeline(pipeline);
 }

 // Print final state
 printf("\n========================================\n");
 printf(" FINAL CPU STATE\n");
 printf("========================================\n");
 printf("Registers: ");
 for (int i = 0; i < NUM_REGISTERS; i++) {
 printf("R%d=%d ", i, cpu.registers[i]);
 }
 printf("\nPC: %d\n", cpu.pc);
 printf("Memory[100] = %d\n", cpu.memory[100]);
 printf("Total cycles: %d\n", cycles);

 return 0;
}
